mapper.select:


    and resource_name like
concat('%', #{resourceName}, '%')
    and
resource_type = #{resourceType}
    and course_id = #{courseId}
    and chapter_id = #{chapterId}
    and uploader_id = #{uploaderId}
    and audit_status = #{auditStatus}
    and status = #{status}

order by quality_score desc, resource_id desc
